
import { SiteHeader } from "@/components/SiteHeader";
import { OrderClient } from "@/components/OrderClient";
import { getVendors, type Vendor } from "@/ai/flows/vendor-flow";
import { getMenusByVendorId } from "@/ai/flows/menu-flow";
import type { MenuItem } from "@/ai/flows/menu-flow";

type Menu = {
  [key: string]: MenuItem[];
};

async function fetchAllMenus(vendors: Vendor[]): Promise<Menu> {
  const menuPromises = vendors.map(async (vendor) => {
    if (!vendor.isActive) return null;
    const menuItems = await getMenusByVendorId(vendor.vendorId);
    return { vendorId: vendor.vendorId, items: menuItems };
  });

  const results = await Promise.all(menuPromises);
  
  const menus: Menu = {};
  for (const result of results) {
    if (result) {
      menus[result.vendorId] = result.items;
    }
  }
  
  return menus;
}


export default async function OrderPage() {
  const vendors = (await getVendors()).filter(v => v.isActive);
  const menus = await fetchAllMenus(vendors);
  
  return (
    <div className="min-h-screen bg-background font-body text-foreground">
      <SiteHeader />
      <main>
        <OrderClient vendors={vendors} menus={menus} />
      </main>
    </div>
  );
}
